<?php require_once 'db.php'; $u=require_login(); $where=$u['role']==='student'?'WHERE b.student_id='.(int)$u['id']:''; $rows=pdo()->query("SELECT b.*,t.table_code,p.transaction_id,p.status payment_status FROM bookings b JOIN library_tables t ON t.id=b.table_id LEFT JOIN payments p ON p.booking_id=b.id $where ORDER BY b.id DESC LIMIT 50")->fetchAll(); app_header('Booking Status'); ?><section class="card wide"><h1>Booking Status</h1><div class="table-wrap"><table><tr><th>ID</th><th>Table</th><th>Plan</th><th>Payment</th><th>Status</th><th>Start</th><th>Expiry</th><th>Reason</th></tr><?php foreach($rows as $r): ?><tr><td>#<?=e($r['id'])?></td><td><?=e($r['table_code'])?></td><td><?=e($r['duration_days'])?> days</td><td><?=e($r['transaction_id'])?> (<?=e($r['payment_status'])?>)</td><td><span class="pill <?=e($r['status'])?>"><?=e($r['status'])?></span></td><td><?=e($r['start_date'])?></td><td><?=e($r['expiry_date'])?></td><td><?=e($r['rejection_reason'])?></td></tr><?php endforeach; ?></table></div></section><?php app_footer(); ?>
